var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"세계는 종말을 되풀이하고, 그 끝에 이면세계라는 잔재를 남겨.","JPN":"世界は終末を繰り返し、その果てに裏世界という残滓を残す。","ENG":"The world repeats its end and leaves remnants called the Counterside.","TWN":"世界不斷重複著終結，並留下了那名為異界的殘骸。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"인류가 침식에 패배하는 순환만이 반복될 뿐. 변수는 일어나지 않아.","JPN":"人類が侵食に負ける循環だけが繰り返されるだけ。変数は発生しない。","ENG":"Only a cycle where humanity loses to Corruption is repeated. Other variables do not occur.","TWN":"人類只會在侵蝕中不斷失敗，重蹈覆轍，沒有任何變數。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"난 탐미엘이라는 신이 만든 <color=#ffd34c>그 순환</color>을 멈추기 위해 내가 할 수 있는 모든 시도를 해봤다네.","JPN":"私はタミエルという神が作った<color=#ffd34c>その循環</color>を止めるために、私にできるすべてのことを試した。","ENG":"I've tried everything in my power to stop the <color=#ffd34c>cycle</color> created by the god Tammiel.","TWN":"我為了阻止名叫塔米爾的神所創造的<color=#ffd34c>那個迴圈</color>，嘗試了我能做的一切。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"물론 내가 아끼는 이들의 죽음을 거스르고 싶다는 충동에 휩싸인 적도 많았어.","JPN":"もちろん、私の大切な人々の死に逆らいたいという衝動に駆られたことも多かった。","ENG":"Of course, there were many times when I was swept by the urge to defy the deaths of those I cared about.","TWN":"當然，這其中也曾多次被想要拯救我所珍惜之人的衝動所困擾。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그 한순간의 충동은 모든 계획을 어그러뜨릴 뿐, <color=#ffd34c>순환</color>을 멈추는 데 도움이 되지 못했고…","JPN":"だが、その一瞬の衝動はすべての計画を乱すだけで、<color=#ffd34c>循環</color>を止めることには役立たず……","ENG":"But that impulse merely derailed all my plans and didn't help stop the <color=#ffd34c>cycle</color>.","TWN":"但是那一瞬間的衝動只會打亂所有計劃，對<color=#ffd34c>迴圈</color>的停止毫無幫助……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"그들에게 쥐어준 일말의 희망은 더 비참한 결말로 이어질 뿐이었지.","JPN":"彼らに与えた一抹の希望は、さらに悲惨な結末に繋がるだけだった。","ENG":"The glimmer of hope they were given only led to a more miserable end.","TWN":"給予他們的一絲希望，只會導致更加悲慘的結局。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"...Yes.","TWN":"……是的。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지난 날의 실패를 없던 셈 칠 수는 없어.","JPN":"過去の失敗をなかったことにはできない。","ENG":"I can't pretend that the past failures never happened.","TWN":"過去的失敗無法被抹去。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이면세계의 짙은 그림자로 남아, <color=#ffd34c>나</color>를 평생 동안 쫓아다닐 테니까.","JPN":"裏世界の濃いシャドウとして残り、一生<color=#ffd34c>私</color>について来るはずだからな。","ENG":"They will remain as a dark shadow of the Counterside, chasing <color=#ffd34c>myself</color> forever.","TWN":"它將會成為異界裡濃重的暗影，並追隨<color=#ffd34c>我</color>一生。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 실패에 얽매여 현실을 망치는 어리석은 선택은 말았으면 해.","JPN":"だが、その失敗に縛られて現実を滅ぼす愚かな選択は止してくれたまえ。","ENG":"But I hope not to get too caught up in those failures and make a foolish choice that will ruin reality.","TWN":"但是我希望你不要因為某次失敗而做出毀掉現世的愚蠢選擇。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그들의 희생에 보답하는 길은 이 <color=#ffd34c>순환</color>을 멈추는 것 뿐이라는 걸.","JPN":"彼らの犠牲に報いる道は、この<color=#ffd34c>循環</color>を止めることだけだということを。","ENG":"The only way to make their sacrifices worth it is to stop this <color=#ffd34c>cycle</color>.","TWN":"回報他們犧牲的唯一方式，就是停止這個<color=#ffd34c>迴圈</color>。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번엔 부디 명심하라고.","JPN":"今回はどうか覚えておけ。","ENG":"Please keep that in mind this time.","TWN":"這次請務必記住了。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"관리자님…?","JPN":"管理者さん……？","ENG":"Administrator...?","TWN":"管理者……？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"저기요오! 이제 일어나셔야죠!","JPN":"あのぉ！　もう起きてください！","ENG":"Hey! It's time to wake up!","TWN":"管理者！該起床了！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"아아- 정말 깊이 잠들었나 보네.","JPN":"ああー本当に熟睡しているみたいだね。","ENG":"Oh... Guess he's still fast asleep.","TWN":"啊啊～看來睡得很香啊。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"헤헤…","JPN":"へへ……","ENG":"Hehe...","TWN":"嘿嘿……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"제 잘못이 아니에요. 이건 관리자님이 부주의한 거라고요.","JPN":"私は悪くないですよ。これは管理者さんの不注意だったんです。","ENG":"It's not my fault. This is because of the Administrator's carelessness.","TWN":"這不是我的錯，這是管理者粗心大意的結果。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼, 잘 먹겠습니다- 앙!","JPN":"じゃあ、いただきまーす。あーん！","ENG":"Then, Bon appetit! AH!","TWN":"那我就不客氣了～啊姆！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"목덜미로 날아오는 것을 잡아챈다.","JPN":"首筋に向かって飛び込んでくるものをつかみ取る。","ENG":"Catch something coming for the back of my neck.","TWN":"抓住從後面飛來的東西。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아핫?!","JPN":"あはっ！？","ENG":"Huh?!","TWN":"啊哈？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 뭘 하려던 거지?","JPN":"今何をしていたのかね？","ENG":"What were you trying to do just now?","TWN":"你剛才想做什麼？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그게 그러니까…","JPN":"それが、えーっと……","ENG":"Well, uh...","TWN":"那個，就是……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"냄새가 너무 좋으셔서 살짝 맛만 보려고 했어요.","JPN":"すっごくいい匂いがしたから、ちょっとだけ味見しようとしたんです。","ENG":"You smelled so good that I just wanted a little taste.","TWN":"因為太香了，我只是想稍微嚐嚐……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래 보이는군.","JPN":"そのようだな。","ENG":"I can see that.","TWN":"我看得出來。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에헤헤…","JPN":"えへへ……","ENG":"Ehehe...","TWN":"欸嘿嘿……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"정마알- 그렇게 관리자님 혼자 주무시면 어떡해요? 현실 부상에 성공한지 벌써 10분이나 지났다구요.","JPN":"もうー管理者さんが1人で寝ちゃうからですよ。現実に浮上してもう10分も経ちましたから。","ENG":"I mean, come on...! How can you still be asleep? It's already been 10 minutes since we returned to the Normalside.","TWN":"真是的～管理者，你怎麼能一個人睡著了呢？距離你成功回到現世已經經過10分鐘了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 사람들은 어디로 갔지?","JPN":"他の人はどこに行った？","ENG":"Where are the others?","TWN":"其他人去哪？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};